/* VCD dumping functions */
MOD_mkFpAdderTestbench & mkFpAdderTestbench_backing(tSimStateHdl simHdl)
{
  static MOD_mkFpAdderTestbench *instance = NULL;
  if (instance == NULL)
  {
    vcd_set_backing_instance(simHdl, true);
    instance = new MOD_mkFpAdderTestbench(simHdl, "top", NULL);
    vcd_set_backing_instance(simHdl, false);
  }
  return *instance;
}
void MODEL_mkFpAdderTestbench::dump_VCD_defs()
{
  (mkFpAdderTestbench_instance->dump_VCD_defs)(vcd_depth(sim_hdl));
}
void MODEL_mkFpAdderTestbench::dump_VCD(tVCDDumpType dt)
{
  (mkFpAdderTestbench_instance->dump_VCD)(dt,
					  vcd_depth(sim_hdl),
					  mkFpAdderTestbench_backing(sim_hdl));
}
